Seems the warning causes by php.mk:
add-plist-phpext:
        @${ECHO_CMD} "lib/php/${PHP_EXT_DIR}/${PHP_MODNAME}.so" \
                >> ${TMPPLIST}
        @${FIND} -P ${STAGEDIR}${PREFIX}/include/php/ext/${PHP_MODNAME} ! -type d 2>/dev/null | \
                ${SED} -ne 's,^${STAGEDIR}${PREFIX}/,,p' >> ${TMPPLIST}
        @${ECHO_CMD} "@exec echo \#include \\\"ext/${PHP_MODNAME}/config.h\\\" >> %D/include/php/ex
t/php_config.h" \
                >> ${TMPPLIST}
        @${ECHO_CMD} "@unexec cp %D/include/php/ext/php_config.h %D/include/php/ext/php_config.h.or
ig" \
                >> ${TMPPLIST}
        @${ECHO_CMD} "@unexec grep -v ext/${PHP_MODNAME}/config.h %D/include/php/ext/php_config.h.o
rig > %D/include/php/ext/php_config.h || true" \
                >> ${TMPPLIST}
        @${ECHO_CMD} "@unexec ${RM} %D/include/php/ext/php_config.h.orig" \
                >> ${TMPPLIST}
        @${ECHO_CMD} "${PHP_EXT_INI_FILE}" \
                >> ${TMPPLIST}
        @${ECHO_CMD} "****************************************************************************" > ${PHP_EXT_PKGMESSAGE}
